## {#module-UI-data-sidebar}

module_UI_data_sidebar <- function(id)
{
  ns <- NS(id)
  tagList(
    uiOutput(ns("data_simu_ui")), 
    uiOutput(ns("set_seed")), 
    module_UI_download_simulation_setting(ns("download_simu_setting")),
    fileInput(ns("uploadSettings"), div(class = "custom-label", "Upload Simulation Settings"), 
              accept = ".rds"),
    hr(), 
    h6("Current Trial: \n"),
    uiOutput(ns("set_total_size")),
    uiOutput(ns("trial_type_ui")),
    uiOutput(ns("UI_data_type")),         # individual or aggregate
    uiOutput(ns("UI_response_type")),     # Binary, Continuous, or Time-to-event
    uiOutput(ns("UI_borrow_type")),       # treatment, control, or both 
    hr(), 
    h6("External Data:"), 
    uiOutput(ns("UI_external_borrow"))
  )
}

module_server_data_sidebar <- function(input, output, session, design_setting_list, all_rv)
{
  ns <- session$ns

  ### UI: update data simulation type: simulate or upload 
  output$data_simu_ui <- renderUI({
    radioButtons(width = 1000, inputId = ns("data_simu"), label = div(class = "custom-label", "Simulate or upload datasets?"), 
                 choices = list("Simulate datasets" = 1, "Upload datasets" = 2), 
                 selected = as.numeric(design_setting_list$data_simu))
  })


  #### UI: set the random seed: 
  output$set_seed <- renderUI({
    ui_parts <- list()
    if(as.numeric(design_setting_list$data_simu) == 1) {
      ui_parts <- c(ui_parts, 
                    list(numericInput(ns("random_seed"), div(class = "custom-label", "Set the random seed:"), 
                                      value = as.numeric(design_setting_list$random_seed), 
                                      min = 1),
                         uiOutput(ns("random_seed_warning")))
      )
    }

    tagList(ui_parts)
  })

  #### UI: set total sample size: 
  output$set_total_size <- renderUI({
    if(as.numeric(design_setting_list$data_simu) == 1) {
      tagList(module_UI_total_sample_size(ns("current_total_size")))
    }
  })

  callModule(module = module_server_total_sample_size, id = "current_total_size", data = all_rv$current_RCT_size_list)

  ### UI: update trial type - single arm trial or RCT 
  output$trial_type_ui <- renderUI({
    radioButtons(inputId = ns("trial_type"), label = div(class = "custom-label", "Trial Type:"), 
                 choices = list("Single-arm Trial" = 1, "Randomized Controlled Trial" = 2), 
                 selected = as.numeric(design_setting_list$trial_type))
  })

  ### UI: update response type choice list based on the trial type 
  output$UI_response_type <- renderUI({
    if (as.numeric(design_setting_list$trial_type) == 1 | as.numeric(design_setting_list$data_type) == 2) {
      radioButtons(inputId = ns("response_type"), label = div(class = "custom-label", "Endpoint Type:"), 
                   choices = list("Binary" = 1, "Continuous" = 2), 
                   selected = ifelse(as.numeric(design_setting_list$response_type) < 3, as.numeric(design_setting_list$response_type), 1))
    } else {
      radioButtons(inputId = ns("response_type"), label = div(class = "custom-label", "Endpoint Type:"), 
                   choices = list("Binary" = 1, "Continuous" = 2, "Time-to-event" = 3), 
                   selected = as.numeric(design_setting_list$response_type))
    }
  })

  ### UI: update borrowing type choice list based on the trial type 
  output$UI_borrow_type <- renderUI({
    if(as.numeric(design_setting_list$trial_type) == 1) {       # Single-arm 
      radioButtons(inputId = ns("borrow_type"), label = div(class = "custom-label", "Which group needs borrowing?"),
                   choices = list("Treatment Group" = 2), 
                   selected = ifelse(as.numeric(design_setting_list$borrow_type) == 2, 2, 2))
    } else if(as.numeric(design_setting_list$trial_type) == 2 && as.numeric(design_setting_list$response_type) < 3) {     # RCT with binary/continuous response 
      radioButtons(inputId = ns("borrow_type"), label = div(class = "custom-label", "Which group needs borrowing?"),
                   choices = list("Control Group" = 1, "Both Groups" = 3), 
                   selected = ifelse(as.numeric(design_setting_list$borrow_type) %in% c(1, 3), as.numeric(design_setting_list$borrow_type), 1))
    } else {               # RCT with TITE response
      radioButtons(inputId = ns("borrow_type"), label = div(class = "custom-label", "Which group needs borrowing?"),
                   choices = list("Control Group" = 1), 
                   selected = ifelse(as.numeric(design_setting_list$borrow_type) == 1, 1, 1))
    }
  })

  ### UI: update data type based on simulating or uploading data 
  output$UI_data_type <- renderUI({
    radioButtons(inputId = ns("data_type"), label = div(class = "custom-label", "Data Type:"), 
                 choices = list("Individual-level" = 1, "Aggregate-level" = 2), 
                 selected = as.numeric(design_setting_list$data_type))
  })

  output$UI_external_borrow <- renderUI({
    ui_parts <- list() 
    # Individual-level data 
    if(as.numeric(design_setting_list$data_type) == 1)
    {
      if(as.numeric(design_setting_list$data_simu) == 1) {
        # ui_parts <- c(ui_parts, list(div("This app simulates a single external dataset at the individual level.")))
        # borrow for one arm 
        if(as.numeric(design_setting_list$borrow_type) == 2) {   
          ui_parts <- c(ui_parts, 
                        list(radioButtons(inputId = ns("external_trial_type"), label = div(class = "custom-label", "Trial Type:"), 
                                          choices = list("One single-arm trial with current treatment" = 1), 
                                          selected = as.numeric(design_setting_list$external_trial_type)))
          )
        } else if(as.numeric(design_setting_list$borrow_type) == 1) {   
          ui_parts <- c(ui_parts, 
                        list(radioButtons(inputId = ns("external_trial_type"), label = div(class = "custom-label", "Trial Type:"), 
                                          choices = list("One single-arm trial with current control" = 1), 
                                          selected = as.numeric(design_setting_list$external_trial_type)))
          )
        } else {    # borrow for both arm                           
          ui_parts <- c(ui_parts,    
                        list(radioButtons(inputId = ns("external_trial_type"), label = div(class = "custom-label", "Trial Type:"), 
                                          choices = list("One randomized controlled trial with both current arms" = 1), 
                                          as.numeric(design_setting_list$external_trial_type)))
          )
        }
      } else {
        ui_parts <- c(ui_parts, 
                      list(numericInput(ns("external_num"), div(class = "custom-label", "Number of External Datasets:"), 
                                        value = ifelse(is.na(as.numeric(design_setting_list$external_num)), 1, as.numeric(design_setting_list$external_num)), 
                                        min = 1, max = 20), 
                           uiOutput(ns("external_num_warning"))
                      )
        )
      }
    } else {    # Aggregate-level data
      if(as.numeric(design_setting_list$data_simu) == 1) {           # simulate data
        if(as.numeric(design_setting_list$trial_type) == 1) {        # single-arm trial 
          ui_parts <- c(ui_parts, 
                        list(radioButtons(inputId = ns("external_trial_type"), label = div(class = "custom-label", "Trial Type:"), 
                                          choices = list("Single-arm trials with current treatment" = 1), 
                                          selected = as.numeric(design_setting_list$external_trial_type)))
          ) 
        } else {  # RCT 
          if(as.numeric(design_setting_list$borrow_type) == 1) {    # hybrid control 
            ui_parts <- c(ui_parts, 
                          list(radioButtons(inputId = ns("external_trial_type"), label = div(class = "custom-label", "Trial Type:"), 
                                            choices = list("Single-arm trials with current control" = 1), 
                                            selected = as.numeric(design_setting_list$external_trial_type)))
            ) 
          } else if(as.numeric(design_setting_list$borrow_type) == 3) {  # borrow both arm 
            ui_parts <- c(ui_parts,    
                          list(radioButtons(inputId = ns("external_trial_type"), label = div(class = "custom-label", "Trial Type:"), 
                                            choices = list("Mixed Trials" = 1), 
                                            as.numeric(design_setting_list$external_trial_type))
                          )
            )
          }
        } 
      } 

      # number of external datasets 
      ui_parts <- c(ui_parts, 
                    list(numericInput(ns("external_num"), div(class = "custom-label", "Number of External Trials:"), 
                                      value = as.numeric(design_setting_list$external_num), 
                                      min = 1, max = 20), 
                         uiOutput(ns("external_num_warning"))
                    )
      )

    }

    tagList(ui_parts)
  })

  # update simulate or upload dataset
  observeEvent(input$data_simu, {
    design_setting_list$data_simu <- input$data_simu 
  })

  # update random seed 
  observeEvent(input$random_seed, {
    design_setting_list$random_seed <- input$random_seed

    tmp <- as.numeric(input$random_seed)
    if(is.na(tmp)) {
      showFeedbackWarning(inputId = ns("random_seed"))
      output$random_seed_warning <- renderUI({
        div(style = "color: red;", "Wrong input!")
      })
    } else {
      hideFeedback(ns("random_seed"))
      output$random_seed_warning <- renderUI({
        div(style = "color: green;", "")
      })
    } 
  })

  observeEvent(input$trial_type, {
    design_setting_list$trial_type <- input$trial_type 
  })

  observeEvent(input$response_type, {
    design_setting_list$response_type <- input$response_type
  })

  observeEvent(input$borrow_type, {
    design_setting_list$borrow_type <- input$borrow_type
  })

  observeEvent(input$data_type, {
    design_setting_list$data_type <- input$data_type
  })

  observeEvent(input$external_num, {
    tmp <- as.numeric(input$external_num) 
    if(is.na(tmp)) {
      showFeedbackWarning(inputId = ns("external_num"))
      output$external_num_warning <- renderUI({
        div(style = "color: red;", "Wrong input!")
      })
    } else if(tmp < 0 | tmp %%1 != 0) {
      showFeedbackWarning(inputId = ns("external_num"))
      output$external_num_warning <- renderUI({
        div(style = "color: red;", "Wrong input!")
      })
    } else if(tmp > 20) {
      showFeedbackWarning(inputId = ns("external_num"))
      output$external_num_warning <- renderUI({
        div(style = "color: red;", "Too many external trials!")
      })
    } else {
      design_setting_list$external_num <- input$external_num

      hideFeedback(ns("external_num"))
      output$external_num_warning <- renderUI({
        div(style = "color: green;", "")
      })
    }
  })

  # Download Simulation setting ####
  callModule(module = module_server_download_simulation_setting, id = "download_simu_setting", all_rv)

  ## Upload Simulation setting  
  observeEvent(input$uploadSettings, {
    req(input$uploadSettings)  # Ensure the input is available
    upload_file <- input$uploadSettings$datapath
    settings_to_load <- readRDS(upload_file)      
    update_all_rvs(all_rv, settings_to_load)   # update all reactiveValues 
    output$uploadStatus <- renderText("Settings uploaded successfully!")
  })

}
